+            if (err instanceof ValidationError) {
+                return res.status(400).json({
+                    error: err.message,
+                    code: 'VALIDATION_ERROR',
+                    details: err.details
+                });
+            }
+            if (err instanceof SwarmError) {
+                return res.status(409).json({
+                    error: err.message,
+                    code: 'SWARM_ERROR',
+                    details: err.details
