+{"version":3,"sources":["../../../../src/cli/agents/architect.ts"],"sourcesContent":["/**
 * Architect Agent - Specialized in system design and architecture
 */

import { BaseAgent } from './base-agent.js';
import type {
  AgentCapabilities,
  AgentConfig,
  AgentEnvironment,
  TaskDefinition,
} from '../../swarm/types.js';
import type { ILogger } from '../../core/logger.js';
import type { IEventBus } from '../../core/event-bus.js';
import type { DistributedMemorySystem } from '../../memory/distributed-memory.js';

// Type definitions for architect analysis
interface ArchitectureIssue {
  category: string;
  severity: string;
  description: string;
  component: string;
  recommendation: string;
}

interface ArchitectureRecommendation {
  category: string;
  priority: string;
  description: string;
  benefits: string[];
  implementation: string;
}

interface ApiEndpoint {
  method: string;
  path: string;
  description: string;
  auth: boolean;
  rateLimit: string;
}

interface MicroserviceComponent {
  service: string;
  purpose: string;
}

interface ServiceComponent {
  name: string;
  responsibility: string;
  database: string;
  api: string;
  dependencies: string[];
}

interface DatabaseComponent {
  name: string;
  type: string;
  purpose: string;
  size: string;
}

interface InfrastructureComponent {
  name: string;
  type: string;
  purpose: string;
  specifications: any;
}

export class ArchitectAgent extends BaseAgent {
  constructor(
    id: string,
    config: AgentConfig,
    environment: AgentEnvironment,
    logger: ILogger,
    eventBus: IEventBus,
    memory: DistributedMemorySystem,
  ) {
    super(id, 'architect', config, environment, logger, eventBus, memory);
  }

  protected getDefaultCapabilities(): AgentCapabilities {
    return {
      codeGeneration: false,
      codeReview: true,
      testing: false,
      documentation: true,
      research: true,
      analysis: true,
      webSearch: true,
      apiIntegration: true,
      fileSystem: true,
      terminalAccess: false,
      languages: ['typescript', 'javascript', 'python', 'java', 'csharp', 'go', 'rust'],
      frameworks: [
        'microservices',
        'kubernetes',
        'docker',
        'aws',
        'azure',
        'gcp',
        'terraform',
        'helm',
      ],
      domains: [
        'system-architecture',
        'software-architecture',
        'cloud-architecture',
        'microservices-design',
        'api-design',
        'database-architecture',
        'security-architecture',
        'scalability-design',
        'infrastructure-design',
        'enterprise-architecture',
      ],
      tools: [
        'architecture-diagrams',
        'system-modeler',
        'design-patterns',
        'cloud-designer',
        'api-designer',
        'security-analyzer',
        'performance-modeler',
        'cost-calculator',
      ],
      maxConcurrentTasks: 2,
      maxMemoryUsage: 1024 * 1024 * 1024, // 1GB
      maxExecutionTime: 2400000, // 40 minutes
      reliability: 0.95,
      speed: 0.7,
      quality: 0.98,
    };
  }

  protected getDefaultConfig(): Partial<AgentConfig> {
    return {
      autonomyLevel: 0.6,
      learningEnabled: true,
      adaptationEnabled: true,
      maxTasksPerHour: 8,
      maxConcurrentTasks: 2,
      timeoutThreshold: 2400000,
      reportingInterval: 90000,
      heartbeatInterval: 20000,
      permissions: ['file-read', 'file-write', 'web-access', 'api-access', 'cloud-access'],
      trustedAgents: [],
      expertise: {
        'system-design': 0.98,
        'architecture-patterns': 0.95,
        scalability: 0.92,
        security: 0.88,
        performance: 0.9,
        'cloud-design': 0.87,
      },
      preferences: {
        architectureStyle: 'microservices',
        cloudProvider: 'multi',
        securityFirst: true,
        scalabilityFocus: true,
        documentationDetail: 'comprehensive',
      },
    };
  }

  override async executeTask(task: TaskDefinition): Promise<any> {
    this.logger.info('Architect executing task', {
      agentId: this.id,
      taskType: task.type,
      taskId: task.id,
    });

    try {
      switch (task.type) {
        case 'system-design':
          return await this.designSystem(task);
        case 'architecture-review':
          return await this.reviewArchitecture(task);
        case 'api-design':
          return await this.designAPI(task);
        case 'cloud-architecture':
          return await this.designCloudArchitecture(task);
        case 'microservices-design':
          return await this.designMicroservices(task);
        case 'security-architecture':
          return await this.designSecurity(task);
        case 'scalability-design':
          return await this.designScalability(task);
        case 'database-architecture':
          return await this.designDatabase(task);
        default:
          return await this.performGeneralDesign(task);
      }
    } catch (error) {
      this.logger.error('Architecture task failed', {
        agentId: this.id,
        taskId: task.id,
        error: error instanceof Error ? error.message : String(error),
      });
      throw error;
    }
  }

  private async designSystem(task: TaskDefinition): Promise<any> {
    const requirements = task.input?.requirements;
    const scale = task.input?.scale || 'medium';
    const constraints = task.input?.constraints || [];
    const style = task.input?.style || 'microservices';

    this.logger.info('Designing system', {
      requirements: requirements?.length || 0,
      scale,
      style,
    });

    const design = {
      requirements,
      scale,
      style,
      architecture: {
        components: [] as any[],
        services: [] as any[],
        databases: [] as any[],
        queues: [] as any[],
        caches: [] as any[],
      },
      patterns: [] as string[],
      technologies: {
        backend: [] as string[],
        frontend: [] as string[],
        database: [] as string[],
        infrastructure: [] as string[],
        monitoring: [] as string[],
      },
      diagrams: [],
      documentation: {
        overview: '',
        components: [],
        apis: [],
        deployment: '',
        monitoring: '',
      },
      constraints: constraints,
      tradeoffs: [],
      risks: [],
      recommendations: [],
      timestamp: new Date(),
    };

    // Store design progress
    await this.memory.store(
      `design:${task.id}:progress`,
      {
        status: 'designing',
        startTime: new Date(),
        requirements,
      },
      {
        type: 'design-progress',
        tags: ['architecture', this.id, style],
        partition: 'tasks',
      },
    );

    // Simulate system design
    await this.delay(5000);

    design.architecture.components = [
      {
        name: 'API Gateway',
        type: 'gateway',
        purpose: 'Request routing and load balancing',
        technology: 'Kong/NGINX',
      },
      {
        name: 'User Service',
        type: 'microservice',
        purpose: 'User management and authentication',
        technology: 'Node.js/Express',
      },
      {
        name: 'Data Service',
        type: 'microservice',
        purpose: 'Data processing and analytics',
        technology: 'Python/FastAPI',
      },
    ] as any[];

    design.patterns = [
      'Microservices Architecture',
      'API Gateway Pattern',
      'Database per Service',
      'Event Sourcing',
      'CQRS',
      'Circuit Breaker',
    ] as string[];

    design.technologies = {
      backend: ['Node.js', 'Python', 'TypeScript'] as string[],
      frontend: ['React', 'TypeScript'] as string[],
      database: ['PostgreSQL', 'Redis', 'MongoDB'] as string[],
      infrastructure: ['Kubernetes', 'Docker', 'AWS'] as string[],
