+{"version":3,"sources":["../../../../src/cli/agents/coder.ts"],"sourcesContent":["/**
 * Coder Agent - Specialized in software development and code generation
 */

import { BaseAgent } from './base-agent.js';
import type {
  AgentCapabilities,
  AgentConfig,
  AgentEnvironment,
  TaskDefinition,
} from '../../swarm/types.js';
import type { ILogger } from '../../core/logger.js';
import type { IEventBus } from '../../core/event-bus.js';
import type { DistributedMemorySystem } from '../../memory/distributed-memory.js';

// Type definitions for coder activities
interface CodeFile {
  path: string;
  content: string;
  type: string;
}

interface TestFile {
  path: string;
  content: string;
  framework: string;
}

interface DatabaseTable {
  name: string;
  columns: string[];
}

export class CoderAgent extends BaseAgent {
  constructor(
    id: string,
    config: AgentConfig,
    environment: AgentEnvironment,
    logger: ILogger,
    eventBus: IEventBus,
    memory: DistributedMemorySystem,
  ) {
    super(id, 'coder', config, environment, logger, eventBus, memory);
  }

  protected getDefaultCapabilities(): AgentCapabilities {
    return {
      codeGeneration: true,
      codeReview: true,
      testing: true,
      documentation: true,
      research: false,
      analysis: true,
      webSearch: false,
      apiIntegration: true,
      fileSystem: true,
      terminalAccess: true,
      languages: [
        'typescript',
        'javascript',
        'python',
        'rust',
        'go',
        'java',
        'cpp',
        'csharp',
        'php',
        'ruby',
        'swift',
        'kotlin',
      ],
      frameworks: [
        'deno',
        'node',
        'react',
        'vue',
        'svelte',
        'angular',
        'express',
        'fastify',
        'nextjs',
        'nuxtjs',
        'django',
        'flask',
        'spring',
        'rails',
      ],
      domains: [
        'web-development',
        'backend-development',
        'frontend-development',
        'api-development',
        'database-design',
        'devops',
        'mobile-development',
        'microservices',
        'fullstack-development',
        'system-architecture',
      ],
      tools: [
        'git',
        'editor',
        'debugger',
        'linter',
        'formatter',
        'compiler',
        'bundler',
        'package-manager',
        'docker',
        'kubernetes',
        'ci-cd',
        'testing-framework',
      ],
      maxConcurrentTasks: 3,
      maxMemoryUsage: 1024 * 1024 * 1024, // 1GB
      maxExecutionTime: 1800000, // 30 minutes
      reliability: 0.95,
      speed: 0.75,
      quality: 0.95,
    };
  }

  protected getDefaultConfig(): Partial<AgentConfig> {
    return {
      autonomyLevel: 0.7,
      learningEnabled: true,
      adaptationEnabled: true,
      maxTasksPerHour: 12,
      maxConcurrentTasks: 3,
      timeoutThreshold: 1800000,
      reportingInterval: 60000,
      heartbeatInterval: 15000,
      permissions: [
        'file-read',
        'file-write',
        'terminal-access',
        'git-access',
        'package-install',
        'docker-access',
      ],
      trustedAgents: [],
      expertise: {
        'code-generation': 0.95,
        debugging: 0.9,
        testing: 0.85,
        refactoring: 0.92,
        architecture: 0.8,
        performance: 0.85,
      },
      preferences: {
        codeStyle: 'functional',
        testFramework: 'jest',
        lintingStrict: true,
        documentation: 'comprehensive',
        errorHandling: 'robust',
      },
    };
  }

  override async executeTask(task: TaskDefinition): Promise<any> {
    this.logger.info('Coder executing task', {
      agentId: this.id,
      taskType: task.type,
      taskId: task.id,
    });

    try {
      switch (task.type) {
        case 'code-generation':
          return await this.generateCode(task);
        case 'code-review':
          return await this.reviewCode(task);
        case 'refactoring':
          return await this.refactorCode(task);
        case 'testing':
          return await this.writeTests(task);
        case 'debugging':
          return await this.debugCode(task);
        case 'api-development':
          return await this.developAPI(task);
        case 'database-design':
          return await this.designDatabase(task);
        case 'performance-optimization':
          return await this.optimizePerformance(task);
        default:
          return await this.performGeneralDevelopment(task);
      }
    } catch (error) {
      this.logger.error('Coding task failed', {
        agentId: this.id,
        taskId: task.id,
        error: error instanceof Error ? error.message : String(error),
      });
      throw error;
    }
  }

  private async generateCode(task: TaskDefinition): Promise<any> {
    const requirements = task.input?.requirements || task.description;
    const language = task.input?.language || 'typescript';
    const framework = task.input?.framework;
    const style = task.input?.style || 'functional';

    this.logger.info('Generating code', {
      requirements,
      language,
      framework,
      style,
    });

    const result = {
      requirements,
      language,
      framework,
      style,
      files: [] as CodeFile[],
      tests: [] as TestFile[],
      documentation: '',
      metrics: {
        linesOfCode: 0,
        complexity: 0,
        testCoverage: 0,
        quality: 0,
      },
      dependencies: [] as string[],
      buildInstructions: [] as string[],
      timestamp: new Date(),
    };

    // Store development progress
    await this.memory.store(
      `code:${task.id}:progress`,
      {
        status: 'generating',
        startTime: new Date(),
        requirements,
      },
      {
        type: 'code-progress',
        tags: ['coding', this.id, language],
        partition: 'tasks',
      },
    );

    // Simulate code generation
    await this.delay(3000);

    result.files = [
      {
        path: `src/main.${this.getFileExtension(language)}`,
        content: this.generateSampleCode(language, requirements),
        type: 'main',
      },
      {
        path: `src/types.${this.getFileExtension(language)}`,
        content: this.generateTypesCode(language),
        type: 'types',
      },
    ];

    result.tests = [
      {
        path: `tests/main.test.${this.getFileExtension(language)}`,
        content: this.generateTestCode(language, requirements),
        framework: 'jest',
      },
    ];

    result.documentation = this.generateDocumentation(requirements, language);
    result.metrics = {
      linesOfCode: 150,
      complexity: 3.2,
      testCoverage: 85,
      quality: 0.92,
    };

    result.dependencies = this.suggestDependencies(language, framework) as any[];
    result.buildInstructions = this.generateBuildInstructions(language, framework) as string[];

    // Store final results
    await this.memory.store(`code:${task.id}:results`, result, {
      type: 'code-results',
      tags: ['coding', 'completed', this.id, language],
      partition: 'tasks',
    });

